\begin{align}
\frac{d}{d x} \arcsin \frac{x}{a}
&= \frac{d \arcsin u}{d u} \frac{d (1/a) x}{d x}\\
&= \frac{1}{\sqrt{1 - (\frac{x}{a})^2}} \cdot \frac{1}{a}\\
&= \frac{1}{a \sqrt{1 - \frac{x^2}{a^2}}}\\
&= \frac{1}{\sqrt{a^2(1 - \frac{x^2}{a^2})}}\\
&= \frac{1}{\sqrt{a^2 - x^2}}\\
\end{align}
